64		private async applyColorMatching(
65			products: IRelatedProduct[],
66			mvRecords: Map<number, IStylesMvBase>,
67			currentStyleColor: IStyleColorBase,
68		): Promise<IRelatedProduct[]> {
69			const colorCache = new Map<
70				number,
71				ReturnType<typeof this.productHydrationService.convertMvColorsToProductColors>
72			>();
73	
74			return Promise.all(
75				products.map(async (product) => {
76					const mv = mvRecords.get(product.style_id);
77					let colors = colorCache.get(product.style_id);
78					if (!colors) {
