80							colors: mv?.colors ?? null,
81						});
82						colorCache.set(product.style_id, colors);
83					}
84					if (colors.length > 0) {
85						const closestColorId = await this.colorMatchWorkerService.findClosestColorId({
86							color: currentStyleColor,
